// Monta caminho e conteudo da nota baseado na acao.
// [Logica identica ao original - este patch NAO toca no roteamento por projeto
//  (M2 do dossie), apenas no body raw do HTTP node abaixo.]
const acao = $input.first().json;
const data = new Date().toISOString().split('T')[0];
const hora = new Date().toTimeString().slice(0,5);

let caminho, conteudo, metodo;

if (acao.acao === 'criar_nota') {
  caminho = `04 - Inbox/${data}-${acao.projeto}.md`;
  conteudo = `---
tipo: inbox
data: ${data}
tags: [inbox, ${acao.projeto}]
---

# ${acao.conteudo.slice(0,50)}

${acao.conteudo}
`;
  metodo = 'PUT';

} else if (acao.acao === 'criar_reuniao') {
  caminho = `04 - Inbox/Reuniao-${data}-${acao.projeto}.md`;
  conteudo = `---
tipo: reuniao
data: ${data}
projeto: ${acao.projeto}
tags: [reuniao, ${acao.projeto}]
---

# Reuniao ${data}

## Discussao
${acao.conteudo}

## Acoes
- [ ] 
`;
  metodo = 'PUT';

} else if (acao.acao === 'criar_task') {
  caminho = acao.destinatario || `04 - Inbox/${data}-tasks.md`;
  conteudo = `
- [ ] ${acao.conteudo} - ${data}
`;
  metodo = 'POST';

} else if (acao.acao === 'registrar_lancamento') {
  caminho = `04 - Inbox/Lancamento-${data}-${acao.projeto}.md`;
  conteudo = `---
tipo: lancamento
data: ${data}
projeto: ${acao.projeto}
tags: [financeiro, ${acao.projeto}]
---

# Lancamento ${data}

${acao.conteudo}
`;
  metodo = 'PUT';

} else if (acao.acao === 'registrar_decisao') {
  caminho = `03 - Decisoes/${data}-${acao.projeto}.md`;
  conteudo = `---
tipo: decisao
data: ${data}
projeto: ${acao.projeto}
status: decidido
tags: [decisao, ${acao.projeto}]
---

# Decisao: ${acao.conteudo.slice(0,50)}

## Decisao tomada
${acao.conteudo}
`;
  metodo = 'PUT';

} else {
  caminho = `04 - Inbox/${data}-${acao.acao}-${acao.projeto}.md`;
  conteudo = `---
tipo: ${acao.acao}
data: ${data}
tags: [${acao.projeto}]
---

${acao.conteudo}
`;
  metodo = 'PUT';
}

return [{ json: { ...acao, obsidian_caminho: caminho, obsidian_conteudo: conteudo, obsidian_metodo: metodo } }];
